  1	import * as React from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import {
  5	  ActionGroup,
  6	  Alert,
  7	  AlertActionCloseButton,
  8	  Button,
  9	  Stack,
 10	  StackItem,
 11	} from '@patternfly/react-core';
 12	
 13	import './EnvironmentFormActions.scss';
 14	
 15	type EnvironmentFormActionsProps = {
 16	  closeError: () => void;
 17	  error?: any;
 18	  isSaveDisabled?: boolean;
 19	  onReload: () => void;
 20	  onSave: () => void;
 21	};
 22	
 23	const EnvironmentFormActions: React.FC<EnvironmentFormActionsProps> = ({
 24	  closeError,
 25	  error,
 26	  isSaveDisabled,
 27	  onReload,
 28	  onSave,
 29	}) => {
 30	  const { t } = useKubevirtTranslation();
 31	  const [success, setSuccess] = React.useState(false);
 32	  const [loading, setLoading] = React.useState(false);
 33	  const [apiError, setApiError] = React.useState<any>();
 34	
 35	  const onSubmit = async () => {
 36	    setLoading(true);
 37	    try {
 38	      await onSave();
 39	      setSuccess(true);
 40	      setApiError(undefined);
 41	    } catch (onSaveError) {
 42	      setApiError(onSaveError);
 43	    } finally {
 44	      setLoading(false);
 45	    }
 46	  };
 47	
 48	  const closeAlert = () => {
 49	    if (apiError) {
 50	      setApiError(undefined);
 51	    } else {
 52	      closeError();
 53	    }
 54	  };
 55	
 56	  return (
 57	    <Stack className="environment-form__buttons">
 58	      <StackItem>
 59	        {(error || apiError) && (
 60	          <Alert
 61	            actionClose={<AlertActionCloseButton onClose={closeAlert} />}
 62	            className="co-alert co-alert--scrollable"
 63	            isInline
 64	            title={t('An error occurred')}
 65	            variant="danger"
 66	          >
 67	            <div className="co-pre-line">{error?.message || apiError?.message}</div>
 68	          </Alert>
 69	        )}
 70	        {success && (
 71	          <Alert
 72	            actionClose={<AlertActionCloseButton onClose={() => setSuccess(false)} />}
 73	            className="co-alert"
 74	            isInline
 75	            title={t('Success')}
 76	            variant="success"
 77	          />
 78	        )}
 79	      </StackItem>
 80	      <StackItem>
 81	        <ActionGroup className="pf-v6-c-form">
 82	          <Button
 83	            isDisabled={isSaveDisabled || loading}
 84	            isLoading={loading}
 85	            onClick={onSubmit}
 86	            type="submit"
 87	            variant="primary"
 88	          >
 89	            {t('Save')}
 90	          </Button>
 91	          <Button onClick={onReload} type="button" variant="secondary">
 92	            {t('Reload')}
 93	          </Button>
 94	        </ActionGroup>
 95	      </StackItem>
 96	    </Stack>
 97	  );
 98	};
 99	
100	export default EnvironmentFormActions;

