 2	import { areEnvironmentsChanged } from '../utils';
 3	
 4	const env1Name = 'test-1';
 5	const env1Serial = '1234';
 6	const env1Disk = 'disk1';
 7	
 8	const env2Name = 'test-2';
 9	const env2Serial = '4321';
10	const env2Disk = 'disk2';
11	
12	describe('utils tests', () => {
13	  describe('areEnvironmentsChanged tests', () => {
14	    it('shuffle Envs', () => {
15	      const initialEnvironments: EnvironmentVariable[] = [
16	        { diskName: env1Disk, kind: EnvironmentKind.secret, name: env1Name, serial: env1Serial },
17	        { diskName: env2Disk, kind: EnvironmentKind.secret, name: env2Name, serial: env2Serial },
18	      ];
19	      const newEnvironment: EnvironmentVariable[] = [
20	        { diskName: env1Disk, kind: EnvironmentKind.secret, name: env2Name, serial: env2Serial },
21	        { diskName: env1Disk, kind: EnvironmentKind.secret, name: env1Name, serial: env1Serial },
22	      ];
23	      expect(areEnvironmentsChanged(newEnvironment, initialEnvironments)).toBeFalsy();
24	    });
25	
26	    it('added Env', () => {
27	      const initialEnvironments: EnvironmentVariable[] = [
28	        { diskName: env2Disk, kind: EnvironmentKind.secret, name: env2Name, serial: env2Serial },
